<?php
namespace App\Models;use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Database\Eloquent\Model;
class ParticipantJobRecommendation extends Model{use HasFactory;protected $fillable=['project_person_id','recommended_by_user_id','external_ref','title','employer','location','source_url','note','recommended_at','viewed_at','dismissed_at','converted_application_id'];protected $casts=['recommended_at'=>'datetime','viewed_at'=>'datetime','dismissed_at'=>'datetime'];public function participation(){return $this->belongsTo(ProjektHasPersonen::class,'project_person_id');}public function recommender(){return $this->belongsTo(User::class,'recommended_by_user_id');}public function application(){return $this->belongsTo(ParticipantApplication::class,'converted_application_id');}}
